protected void new()
{
    super(classStr(ETGZRASmartInvoiceService), methodStr(ETGZRASmartInvoiceService, process), SysOperationExecutionMode::Synchronous);
}

public ClassDescription defaultCaption()
{
    return "ZRA Smart Invoice Batch Job ";
}

public static ETGZRASmartIncoiceControleer construct(SysOperationExecutionMode _executionMode = SysOperationExecutionMode::Synchronous)
{
    ETGZRASmartIncoiceControleer controller;
    controller = new ETGZRASmartIncoiceControleer();
    controller.parmExecutionMode(_executionMode);
    return controller;
}

public static void main(Args _args)
{
    ETGZRASmartIncoiceControleer controller;
    controller = ETGZRASmartIncoiceControleer::construct();
    controller.parmArgs(_args);
    controller.startOperation();
}
